// Este código assume que o payload está no formato de array, como no seu exemplo
const result = [];

for (const item of items) {
  // Fazendo o parse do content (transformar string em JSON)
  const contentData = JSON.parse(item.json.content);

  // Montando o novo objeto com as informações desejadas
  result.push({
    json: {
      deliveryTag: item.json.fields.deliveryTag,
      redelivered: item.json.fields.redelivered,
      ...contentData // Espalha os campos do content direto no json final
    }
  });
}

return result;

const item = items[0].json;
const sessionId = item.sessionId;

// Array com todas as mensagens da conversa do Fernando
const mensagens = [
  item.mensagem1, item.mensagem2, item.mensagem3, item.mensagem4,
  item.mensagem5, item.mensagem6, item.mensagem7, item.mensagem8,
  item.mensagem9, item.mensagem10, item.mensagem11, item.mensagem12,
  item.mensagem13, item.mensagem14, item.mensagem15, item.mensagem16
];

// Criar um item para cada mensagem
const resultado = [];
mensagens.forEach((mensagem) => {
  if (mensagem) { // Só adiciona se a mensagem existir
    resultado.push({
      json: {
        mensagem: mensagem,
        sessionId: sessionId
      }
    });
  }
});

return resultado;

