// n8n Code node (JavaScript)

function ensureString(v) {
  if (v == null) return '';
  return typeof v === 'string' ? v : JSON.stringify(v);
}

// Pega mensagem do Normalizador (primeiro item)
const normalizadorMsg = ensureString($('Normalizador').first().json?.message);

// Pega saída do AI Agent (tenta manter o pareamento; se não houver, cai no first())
const aiItemOutput = $('AI Agent').item?.json?.output;
const aiFirstOutput = $('AI Agent').first().json?.output;
const aiOutput = ensureString(aiItemOutput ?? aiFirstOutput ?? '');

// Retorna dois itens
return [
  {
    json: {
      type: "human",
      content: normalizadorMsg,
      additional_kwargs: {},
      response_metadata: {}
    }
  },
  {
    json: {
      type: "ai",
      content: aiOutput,
      tool_calls: [],
      additional_kwargs: {},
      response_metadata: {},
      invalid_tool_calls: []
    }
  }
];
